        code: `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// C lacks dynamic vectors; we cap at the maximum 4^4 = 256 combinations
// (digits length ≤ 4 per LC constraints; 7/9 contribute 4 letters each).
static const char* MAP[] = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};

static void backtrack(const char* digits, int i, int n, char* path, char** out, int* count) {
    if (i == n) {
        path[n] = '\\0';
        out[*count] = strdup(path);
        (*count)++;
        return;
    }
    const char* letters = MAP[digits[i] - '0'];
    for (int k = 0; letters[k]; k++) {
        path[i] = letters[k];
        backtrack(digits, i + 1, n, path, out, count);
    }
}

char** letterCombinations(char* digits, int* returnSize) {
    int n = strlen(digits);
    if (n == 0) { *returnSize = 0; return NULL; }
    char** out = (char**)malloc(sizeof(char*) * 1024);
    char path[16];
    int count = 0;
    backtrack(digits, 0, n, path, out, &count);
    *returnSize = count;
    return out;
}`,
