        code: `#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<string> generateParenthesis(int n) {
        vector<string> result;
        string cur;
        function<void(int, int)> dfs = [&](int open, int close) {
            if ((int)cur.size() == 2 * n) {
                result.push_back(cur);
                return;
            }
            if (open < n) {
                cur.push_back('(');
                dfs(open + 1, close);
                cur.pop_back();
            }
            if (close < open) {
                cur.push_back(')');
                dfs(open, close + 1);
                cur.pop_back();
            }
        };
        dfs(0, 0);
        return result;
    }
};`,
