        code: `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static void dfs(char** result, int* count, char* cur, int len, int open, int close, int n) {
    if (len == 2 * n) {
        result[*count] = (char*)malloc((size_t)(len + 1));
        memcpy(result[*count], cur, (size_t)len);
        result[*count][len] = '\\0';
        (*count)++;
        return;
    }
    if (open < n) {
        cur[len] = '(';
        dfs(result, count, cur, len + 1, open + 1, close, n);
    }
    if (close < open) {
        cur[len] = ')';
        dfs(result, count, cur, len + 1, open, close + 1, n);
    }
}

char** generateParenthesis(int n, int* returnSize) {
    // Catalan(n) <= 2^(2n); 1 << (2*n) is a safe upper bound on the count.
    int cap = 1 << (2 * n);
    char** result = (char**)malloc((size_t)cap * sizeof(char*));
    char* cur = (char*)malloc((size_t)(2 * n + 1));
    *returnSize = 0;
    dfs(result, returnSize, cur, 0, 0, 0, n);
    free(cur);
    return result;
}`,
