        code: `import java.util.*;

class Solution {
    public int ladderLength(String beginWord, String endWord, List<String> wordList) {
        Set<String> wordSet = new HashSet<>(wordList);
        if (!wordSet.contains(endWord)) return 0;
        int L = beginWord.length();
        Map<String, List<String>> patterns = new HashMap<>();
        for (String word : wordSet) {
            for (int i = 0; i < L; i++) {
                String pat = word.substring(0, i) + "*" + word.substring(i + 1);
                patterns.computeIfAbsent(pat, k -> new ArrayList<>()).add(word);
            }
        }
        Set<String> visited = new HashSet<>();
        visited.add(beginWord);
        Queue<Object[]> queue = new ArrayDeque<>();
        queue.offer(new Object[]{beginWord, 1});
        while (!queue.isEmpty()) {
            Object[] front = queue.poll();
            String word = (String) front[0];
            int level = (int) front[1];
            if (word.equals(endWord)) return level;
            for (int i = 0; i < L; i++) {
                String pat = word.substring(0, i) + "*" + word.substring(i + 1);
                for (String nb : patterns.getOrDefault(pat, Collections.emptyList())) {
                    if (visited.contains(nb)) continue;
                    visited.add(nb);
                    queue.offer(new Object[]{nb, level + 1});
                }
                patterns.put(pat, Collections.emptyList());
            }
        }
        return 0;
    }
}`,
