      cpp: {
        code: `#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> kClosest(vector<vector<int>>& points, int k) {
        auto dist = [](const vector<int>& p) { return p[0] * p[0] + p[1] * p[1]; };
        priority_queue<pair<int, vector<int>>> heap;  // max-heap on distance
        for (auto& p : points) {
            heap.push({dist(p), p});
            if ((int)heap.size() > k) heap.pop();
        }
        vector<vector<int>> result;
        while (!heap.empty()) {
            result.push_back(heap.top().second);
            heap.pop();
        }
        sort(result.begin(), result.end(), [&](const vector<int>& a, const vector<int>& b) {
            int da = dist(a), db = dist(b);
            if (da != db) return da < db;
            if (a[0] != b[0]) return a[0] < b[0];
            return a[1] < b[1];
        });
        return result;
    }
};`,
        complexity: { time: 'O(n log k)', space: 'O(k)' },
        approach: 'std::priority_queue is a max-heap by default — perfect for "keep the smallest k by evicting the largest". Final stable sort on (dist, x, y) for deterministic output.',
      },
