        code: `#include <stdlib.h>

// Idiomatic C for this problem needs a binary heap of (distance, point) pairs
// over malloc'd 2D rows, plus the deterministic (dist, x, y) sort tiebreaker.
// That's ~120 lines of malloc bookkeeping that buries the actual algorithm.
// Interview-friendly fallback: qsort the whole array by (dist, x, y) and slice.
static int* sortDist;

int kClosestCmp(const void* a, const void* b) {
    int ia = *(const int*)a, ib = *(const int*)b;
    if (sortDist[ia] != sortDist[ib]) return sortDist[ia] - sortDist[ib];
    return ia - ib;
}

int** kClosest(int** points, int pointsSize, int* pointsColSize,
               int k, int* returnSize, int** returnColumnSizes) {
    int* dists = (int*)malloc(pointsSize * sizeof(int));
    int* idx = (int*)malloc(pointsSize * sizeof(int));
    for (int i = 0; i < pointsSize; i++) {
        dists[i] = points[i][0] * points[i][0] + points[i][1] * points[i][1];
        idx[i] = i;
    }
    sortDist = dists;
    qsort(idx, pointsSize, sizeof(int), kClosestCmp);
    int** result = (int**)malloc(k * sizeof(int*));
    *returnColumnSizes = (int*)malloc(k * sizeof(int));
    for (int i = 0; i < k; i++) {
        result[i] = (int*)malloc(2 * sizeof(int));
        result[i][0] = points[idx[i]][0];
        result[i][1] = points[idx[i]][1];
        (*returnColumnSizes)[i] = 2;
    }
    free(dists);
    free(idx);
    *returnSize = k;
    return result;
}`,
        complexity: { time: 'O(n log n)', space: 'O(n)' },
        approach: 'A real C heap of (dist, point*) plus the dedup-tiebreak sort would dwarf the algorithm. Ship qsort over an index array — caller frees the row-by-row malloc, as LC expects.',
