  const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
  const dfs = (r, c, mark) => {
    mark[r][c] = true;
    for (const [dr, dc] of dirs) {
      const nr = r + dr, nc = c + dc;
      if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;
      if (mark[nr][nc] || heights[nr][nc] < heights[r][c]) continue;
      dfs(nr, nc, mark);
    }
  };
