        code: `func pacificAtlantic(heights [][]int) [][]int {
    if len(heights) == 0 || len(heights[0]) == 0 {
        return [][]int{}
    }
    rows, cols := len(heights), len(heights[0])
    pac := make([][]bool, rows)
    atl := make([][]bool, rows)
    for i := range pac {
        pac[i] = make([]bool, cols)
        atl[i] = make([]bool, cols)
    }
    dirs := [4][2]int{{1, 0}, {-1, 0}, {0, 1}, {0, -1}}
    var dfs func(r, c int, mark [][]bool)
    dfs = func(r, c int, mark [][]bool) {
        mark[r][c] = true
        for _, d := range dirs {
            nr, nc := r+d[0], c+d[1]
            if nr < 0 || nr >= rows || nc < 0 || nc >= cols {
                continue
            }
            if mark[nr][nc] || heights[nr][nc] < heights[r][c] {
                continue
            }
            dfs(nr, nc, mark)
        }
    }
    for c := 0; c < cols; c++ {
        dfs(0, c, pac)
        dfs(rows-1, c, atl)
    }
    for r := 0; r < rows; r++ {
        dfs(r, 0, pac)
        dfs(r, cols-1, atl)
    }
    result := [][]int{}
    for r := 0; r < rows; r++ {
        for c := 0; c < cols; c++ {
            if pac[r][c] && atl[r][c] {
                result = append(result, []int{r, c})
            }
        }
    }
    sort.Slice(result, func(a, b int) bool {
        if result[a][0] != result[b][0] {
            return result[a][0] < result[b][0]
        }
        return result[a][1] < result[b][1]
    })
    return result
}`,
