        code: `func maxSlidingWindow(nums []int, k int) []int {
    dq := make([]int, 0, len(nums))
    result := make([]int, 0, len(nums)-k+1)
    for i, x := range nums {
        for len(dq) > 0 && dq[0] <= i-k {
            dq = dq[1:]
        }
        for len(dq) > 0 && nums[dq[len(dq)-1]] <= x {
            dq = dq[:len(dq)-1]
        }
        dq = append(dq, i)
        if i >= k-1 {
            result = append(result, nums[dq[0]])
        }
    }
    return result
}`,
