        code: `int cmpInt(const void* a, const void* b) {
    int ia = *(const int*)a, ib = *(const int*)b;
    return (ia > ib) - (ia < ib);
}
int* intersect(int* nums1, int nums1Size, int* nums2, int nums2Size, int* returnSize) {
    int* sorted1 = (int*)malloc(sizeof(int) * nums1Size);
    int* sorted2 = (int*)malloc(sizeof(int) * nums2Size);
    memcpy(sorted1, nums1, sizeof(int) * nums1Size);
    memcpy(sorted2, nums2, sizeof(int) * nums2Size);
    qsort(sorted1, nums1Size, sizeof(int), cmpInt);
    qsort(sorted2, nums2Size, sizeof(int), cmpInt);
    int cap = nums1Size < nums2Size ? nums1Size : nums2Size;
    int* result = (int*)malloc(sizeof(int) * cap);
    int i = 0, j = 0, k = 0;
    while (i < nums1Size && j < nums2Size) {
        if (sorted1[i] == sorted2[j]) {
            result[k++] = sorted1[i];
            i++;
            j++;
        } else if (sorted1[i] < sorted2[j]) {
            i++;
        } else {
            j++;
        }
    }
    *returnSize = k;
    free(sorted1);
    free(sorted2);
    return result;
}`,
