      c: {
        code: `#include <stdio.h>
#include <stdlib.h>

static int find(int* p, int x) {
    while (p[x] != x) { p[x] = p[p[x]]; x = p[x]; }
    return x;
}

int countComponents(int n, int** edges, int edgesSize, int* edgesColSize) {
    int* p = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) p[i] = i;
    int count = n;
    for (int i = 0; i < edgesSize; i++) {
        int ra = find(p, edges[i][0]), rb = find(p, edges[i][1]);
        if (ra != rb) { p[ra] = rb; count--; }
    }
    free(p);
    return count;
}`,
        complexity: { time: 'O((V+E) * a(n))', space: 'O(n)' },
        approach: 'Manual malloc for parent array; free at end.',
      },
      go: {
        code: `func countComponents(n int, edges [][]int) int {
    parent := make([]int, n)
    for i := range parent { parent[i] = i }
    var find func(int) int
    find = func(x int) int {
        for parent[x] != x { parent[x] = parent[parent[x]]; x = parent[x] }
        return x
    }
    count := n
    for _, e := range edges {
        ra, rb := find(e[0]), find(e[1])
        if ra != rb { parent[ra] = rb; count-- }
    }
    return count
}`,
        complexity: { time: 'O((V+E) * a(n))', space: 'O(n)' },
        approach: 'Named closure for find with path compression.',
      },
