        code: `class Solution:
    def longestPalindrome(self, s):
        from collections import Counter
        cnt = Counter(s)
        result = 0
        has_odd = False
        for c in cnt.values():
            result += (c // 2) * 2
            if c % 2 == 1:
                has_odd = True
        return result + (1 if has_odd else 0)`,
