        code: `function addBinary(a, b) {
  let i = a.length - 1, j = b.length - 1, carry = 0;
  const out = [];
  while (i >= 0 || j >= 0 || carry) {
    let s = carry;
    if (i >= 0) s += +a[i--];
    if (j >= 0) s += +b[j--];
    out.push(s % 2);
    carry = (s / 2) | 0;
  }
  return out.reverse().join('');
}`,
