        code: `class Solution:
    def findTheWinner(self, n: int, k: int) -> int:
        # Josephus DP — f(i) is the 0-indexed survivor for a circle of size i.
        f = 0
        for i in range(2, n + 1):
            f = (f + k) % i
        return f + 1`,
