    const c = word[r];
    if (!(c in order)) { l = r + 1; distinct = 0; continue; }
    if (r === l) {
      distinct = 1;
    } else {
      const prev = word[r - 1];
      if (order[c] < order[prev]) { l = r; distinct = 1; }
      else if (order[c] > order[prev]) distinct += 1;
    }
    if (distinct === 5) best = Math.max(best, r - l + 1);
