        code: `func longestBeautifulSubstring(word string) int {
    order := [128]int{}
    for i := range order {
        order[i] = -1
    }
    order['a'] = 0
    order['e'] = 1
    order['i'] = 2
    order['o'] = 3
    order['u'] = 4
    best, l, distinct := 0, 0, 0
    for r := 0; r < len(word); r++ {
        oc := order[word[r]]
        if oc < 0 {
            l = r + 1
            distinct = 0
            continue
        }
        if r == l {
            distinct = 1
        } else {
            op := order[word[r-1]]
            if oc < op {
                l = r
                distinct = 1
            } else if oc > op {
                distinct++
            }
        }
        if distinct == 5 && r-l+1 > best {
            best = r - l + 1
        }
    }
    return best
}`,
