        code: `class Solution {
    public int[] sortArrayByParity(int[] nums) {
        int l = 0, r = nums.length - 1;
        while (l < r) {
            if (nums[l] % 2 == 0) { l++; continue; }
            if (nums[r] % 2 == 1) { r--; continue; }
            int tmp = nums[l]; nums[l] = nums[r]; nums[r] = tmp;
            l++;
            r--;
        }
        return nums;
    }
}`,
